// DashboardUpdated is the resolver for the dashboardUpdated field.
func (r *subscriptionResolver) DashboardUpdated(ctx context.Context) (<-chan *generated.DashboardStats, error) {
	oid, err := r.svc.OrgID(ctx)
	if err != nil {
		return nil, err
	}
	ch := r.svc.Realtime.SubscribeDashboard(oid)
	go func() {
		<-ctx.Done()
		r.svc.Realtime.UnsubscribeDashboard(oid, ch)
	}()
	return ch, nil
}

